px;\n  font-style: normal;\n  font-weight: 700;\n  line-height: normal;\n}\n\n.section-heading {\n  display: flex;\n  justify-content: center;\n}\n\n/*----------------------\n PRICING\n-----------------------*/\n.price-block {\n  margin: 20px 0px 30px;\n}\n.price-block h2 {\n  font-size: 80px;\n  font-weight: 700;\n  position: relative;\n  display: inline-block;\n}\n.price-block h2 small {\n  position: absolute;\n  top: 20px;\n  font-size: 16px;\n  left: -9px;\n}\n.price-block h6 {\n  font-size: 14px;\n  border-top: 1px solid #eee;\n  border-bottom: 1px solid #eee;\n  padding: 7px;\n  text-transform: capitalize;\n  width: 50%;\n  margin: 10px auto;\n}\n\n.price-features {\n  margin: 30px 0px 50px;\n}\n.price-features li {\n  font-size: 16px;\n  padding: 5px 0px;\n  position: relative;\n  padding-left: 30px;\n}\n.price-features li:before {\n  position: absolute;\n  content: \"\\f00c\";\n  font-family: \"Font Awesome 5 Free\";\n  left: 0px;\n  top: 5px;\n  color: #21c87a;\n  font-weight: 900;\n}\n\n.pricing-block .price-features li {\n  padding-left: 0px;\n}\n.pricing-block .price-features li:before {\n  display: none;\n}\n\n/*--------------------------\nPRICING-2\n---------------------------*/\n.pricing-box {\n  border: 1px solid #eee;\n  padding: 60px;\n  -webkit-transition: all 300ms ease-in-out;\n  -o-transition: all 300ms ease-in-out;\n  transition: all 300ms ease-in-out;\n}\n.pricing-box .price-block h2 span {\n  font-size: 12px;\n  font-weight: normal;\n  text-transform: capitalize;\n}\n.pricing-box:hover {\n  background: rgb(29, 28, 28);\n  border-color: rgb(29, 28, 28);\n}\n.pricing-box:hover .price-features li {\n  color: #eee;\n}\n.pricing-box:hover .price-block h2 {\n  color: #fff;\n}\n.pricing-box:hover h3 {\n  color: #fff;\n}\n.pricing-box:hover .btn {\n  background: #fff !important;\n  color: #000 !important;\n}\n\n/*----------------------\n BLOG SECTION\n-----------------------*/\n.blog-box {\n  position: relative;\n  display: flex;\n  flex-direction: column;\n  align-items: center;\n  height: 100%;\n}\n.blog-box .blog-img-box img {\n  width: 100%;\n  border-radius: 10px;\n  box-shadow: 0px 2px 10px 0px rgba(0, 0, 0, 0.14);\n  object-fit: contain;\n  aspect-ratio: 16/11;\n  background-color: #101010;\n}\n\n.single-blog {\n  padding-top: 25px;\n  position: relative;\n  height: 100%;\n}\n\n.bg-light .single-blog {\n  padding: 40px;\n  text-align: center;\n  border-bottom: 1px solid #eee;\n}\n\n.blog-content {\n  display: flex;\n  flex-direction: column;\n  height: 100%;\n  flex-grow: 1;\n}\n.blog-content a h3 {\n  color: var(--text-color, #2c2c2c);\n  font-size: 20px;\n  font-style: normal;\n  font-weight: 600;\n  line-height: normal;\n}\n.blog-content p {\n  color: var(--text-color, #2C2C2C);\n  font-size: 14px;\n  font-style: normal;\n  font-weight: 400;\n  line-height: normal;\n}\n.blog-content .link {\n  font-weight: 500;\n  color: #30AB89;\n}\n\n/*------------------------------------\nSECTION TESTIMONIAL\n-------------------------------------*/\n#section-testimonial {\n  position: relative;\n  padding: 20px;\n  -webkit-background-size: cover;\n  background-size: cover;\n  background-color: #101010;\n}\n\n.mb25 {\n  margin-bottom: 25px;\n}\n\n.testimonial-container {\n  margin: auto;\n  max-width: 1540px;\n  margin: 80px auto;\n}\n@media (max-width: 1154px) {\n  .testimonial-container {\n    margin: 50px auto;\n  }\n}\n\n.test-inner {\n  display: flex;\n  padding: 24px;\n  flex-direction: column;\n  justify-content: center;\n  align-items: flex-start;\n  gap: 22px;\n  color: var(--white-color, #FAFAFA);\n  font-size: 14px;\n  font-style: normal;\n  font-weight: 400;\n  line-height: normal;\n  border-radius: 32px;\n  border: 2px solid var(--main-color-1, #30AB89);\n  min-height: 254px;\n}\n@media screen and (max-width: 768px) {\n  .test-inner {\n    margin-bottom: 1rem;\n  }\n}\n\n.test-author-thumb {\n  align-items: center;\n  gap: 1rem;\n}\n.test-author-thumb img {\n  width: 56px;\n  height: 56px;\n  border-ra