er {\n    width: 550px;\n  }\n}\n@media screen and (max-width: 1200px) {\n  .workFlow-body .workflowContainer {\n    width: 500px;\n  }\n  .workFlow-body h3 {\n    font-size: 25px;\n  }\n  .allCards {\n    transform: translate(-70%, 0);\n  }\n  .evencompleteCard {\n    transform: translateX(40%);\n  }\n}\n@media screen and (max-width: 1070px) {\n  .workFlow-body h3 {\n    font-size: 19px;\n  }\n  .workFlow-body .workflowContainer {\n    font-size: 16px;\n  }\n  .workFlow-body .workflowContainer {\n    width: 400px;\n  }\n  .allCards {\n    transform: translate(-78%, 0);\n  }\n  .evencompleteCard {\n    transform: translateX(55%);\n  }\n  .imageContainer {\n    width: 110px;\n  }\n}\n@media screen and (max-width: 850px) {\n  .workflowCenterStick {\n    width: 18px;\n  }\n  .workFlow-body h3 {\n    font-size: 16px;\n  }\n  .workFlow-body .workflowContainer {\n    width: 250px;\n    font-size: 12px;\n    margin-top: 0.5rem;\n  }\n  .imageContainer {\n    width: auto;\n    height: auto;\n    transform: translateY(0);\n  }\n  .imageContainer > img {\n    width: 90px;\n  }\n  .completeCard {\n    justify-content: center;\n    gap: 2rem;\n  }\n  .allCards {\n    transform: translate(-70%, 0);\n    min-height: 900px;\n  }\n  .evencompleteCard {\n    transform: translateX(40%);\n    justify-content: center;\n  }\n  .evencompleteCard > .imageContainer > img {\n    text-align: right;\n  }\n}\n@media screen and (max-width: 560px) {\n  .workFlow-body .workflowContainer {\n    width: 150px;\n    font-size: 9px;\n  }\n  .allCards {\n    transform: translate(-65%, 0);\n  }\n  .imageContainer > img {\n    width: 70px;\n  }\n  .workFlow-body h3 {\n    width: 150px;\n    font-size: 12px;\n    line-height: 20px;\n  }\n  .evencompleteCard {\n    transform: translateX(34%);\n  }\n}\n.service-content h1 {\n  color: #1b1b1b;\n  font-size: 32px;\n  font-style: normal;\n  font-weight: 600;\n  line-height: 50px; /* 142.857% */\n}\n\n.service-content h1 span {\n  color: #30AB89;\n  font-weight