sition: relative;\n}\n\n@media (max-width: 991px) {\n  .what-we-offer #service-heading {\n    text-align: center;\n  }\n}\n\n.what-we-offer .accordion-btn::after {\n  position: absolute;\n  content: \"\";\n  right: 0;\n  top: 28px;\n  width: 20px;\n  height: 20px;\n  background: url(/images/services-page/ph_plus-light.svg);\n  opacity: 0;\n  animation: 1s customAccordionAnimation ease-in-out forwards;\n}\n\n.accordion-btn:not(.collapsed)::after {\n  background: url(/images/services-page/ph_minus.svg);\n  animation: 1s customAccordionAnimation ease-in-out forwards;\n}\n\n@keyframes customAccordionAnimation {\n  0% {\n    opacity: 0.5;\n  }\n  100% {\n    opacity: 1;\n  }\n}\n.what-we-offer .accordion-btn:hover {\n  text-decoration: none;\n}\n\n.what-we-offer .card-header {\n  padding: 0;\n  border: 0px;\n  background: transparent;\n}\n\n.what-we-offer .card {\n  border: 0;\n  border-bottom: 1px solid #c8c8c8 !important;\n  border-radius: 0px !important;\n}\n\n.what-we-offer .card .card-body {\n  padding: 0px 0px 24px;\n}\n\n.process-steps {\n  background-color: #f1f1f1;\n  overflow: hidden;\n}\n\n.section--full,\n.section--vertical {\n  min-height: 50vh;\n  position: relative;\n}\n\n.block-list {\n  white-space: nowrap;\n  padding-left: 100px !important;\n}\n\n.block-list__item {\n  width: 415px;\n  margin-right: 70px;\n  display: inline-block;\n  white-space: normal;\n}\n\n.block-list__item-inner {\n  width: 100%;\n  height: 100%;\n  position: relative;\n}\n\n.block-list__item-inner::before {\n  counter-increment: element;\n  content: counter(element);\n  position: absolute;\n  left: -55px;\n  width: 35px;\n  height: 35px;\n  top: 50%;\n  transform: translateY(-55%);\n  border: 1px solid #2C2C2C;\n  border-radius: 50%;\n  display: flex;\n  justify-content: center;\n  align-items: center;\n  font-size: 20px;\n  font-style: normal;\n  font-weight: 600;\n  line-height: 35px;\n  color: #2C2C2C;\n}\n\n.block-list__item:first-child {\n  margin-left: 0;\n}\n\n#third {\n  background: #f5f5f5;\n}\n\n.scrollend {\n  transform: translateX(-1500px);\n}\n\n.block-list {\n  counter-reset: element;\n  list-style: none;\n}\n\n.scroll-content .mobile {\n  display: none;\n}\n\n@media (max-width: 767px) {\n  .section--vertical.desktop {\n    display: none;\n  }\n  .block-list__item-inner::before {\n    display: none;\n  }\n  .scroll-content .mobile {\n    display: block;\n  }\n}","$light: #fff;\r\n$primary-color: #30AB89;\r\n$primary-colors: #30AB89;\r\n$primary-color: #21c87a;\r\n$primary-background-gradient: linear-gradient(180deg, #61E1BE 0%, rgba(118, 211, 246, 0.25) 100%);\r\n$secondary-color: #F4F7FC;\r\n$black-text: #2C2C2C;\r\n$black: #212529;\r\n$black-light: #6c757d;\r\n$black-lighter: #888;\r\n$border-color:#eee;\r\n$primary-font: \"Plus Jakarta Sans\", sans-serif;\r\n$secondary-font:\"Plus Jakarta Sans\", sans-serif;\r\n$green-border : radial-gradient(circle at 100% 100%, #ffffff 0, #ffffff 8px, transparent 8px) 0% 0%/10px 10px no-repeat,\r\nradial-gradient(circle at 0 100%, #ffffff 0, #ffffff 8px, transparent 8px) 100% 0%/10px 10px no-repeat,\r\nradial-gradient(circle at 100% 0, #ffffff 0, #ffffff 8px, transparent 8px) 0% 100%/10px 10px no-repeat,\r\nradial-gradient(circle at 0 0, #ffffff 0, #ffffff 8px, transparent 8px) 100% 100%/10px 10px no-repeat,\r\nlinear-gradient(#ffffff, #ffffff) 50% 50%/calc(100% - 4px) calc(100% - 20px) no-repeat,\r\nlinear-gradient(#ffffff, #ffffff) 50% 50%/calc(100% - 20px) calc(100% - 4px) no-repeat,\r\nlinear-gradient(13deg, rgba(48,171,137,1) 0%, rgba(25,223,209,1) 100%);\r\n$darkGreenSpan: #187F5F;\r\n$image-background-banner: #7ED4BD;\r\n$service-card-gradient: linear-gradient(180deg, rgb(21, 184, 152) 0%, rgb(96, 129, 209) 100%);\r\n$service-card-button-gradient: linear-gradient(180deg, rgb(97, 225, 190) 0%, rgba(118, 211, 246, 0.2469362745) 100%);\r\n$service-card-button-dropShadow-color:#013b6b;\r\n$underline-color: #61e1be;\r\n$span-background: #2b9778;","/*--------------------\r\nCommon Styles\r\n-----------------*/\r\n\r\n// @media (min-width: 1200px) {\r\n//   .container{\r\n//   }\r\n// }\r\n\r\nimg {\r\n  vertical-align: middle;\r\n  border-style: none;\r\n}\r\n\r\n.img-thumbnail {\r\n  padding: 0.25rem;\r\n  border: 1px solid #dee2e6;\r\n  background-color: #fff;\r\n}\r\n\r\n.section {\r\n  position: relative;\r\n  padding: 8.125rem 0;\r\n}\r\n\r\n@media (min-width: 768px) {\r\n  .section {\r\n    padding: 4.5rem 0;\r\n  }\r\n}\r\n\r\n.section-top {\r\n  padding-top: 8.125rem;\r\n}\r\n\r\n.section-bottom {\r\n  padding-bottom: 8.125rem;\r\n}\r\n\r\n@media (min-width: 768px) {\r\n  .section-top {\r\n    padding-top: 10.3125rem;\r\n  }\r\n}\r\n\r\n.bg-grey {\r\n  background: #f4f7fc;\r\n}\r\n\r\n/*-------------------\r\n  BUTTONS STYLE\r\n----------------=----*/\r\n\r\n.btn {\r\n  font-size: 0.6875rem;\r\n  font-weight: 700;\r\n  position: relative;\r\n  text-transform: uppercase;\r\n  padding: 1rem 2.4rem;\r\n  border: 0.1rem solid transparent;\r\n  transition: all 0.2s ease-in-out;\r\n  letter-spacing: 0.5px;\r\n}\r\n\r\n.btn-primary-border {\r\n  border-radius: 8px;\r\n  border: 3px solid #30ab89;\r\n  font-size: 0.875rem;\r\n}\r\n.btn-circle {\r\n  display: inline-flex;\r\n  width: 4.20313rem !important;\r\n  height: 4.20313rem !important;\r\n  padding: 0 !important;\r\n  border-radius: 50%;\r\n  align-items: center;\r\n  justify-content: center;\r\n}\r\n\r\n.btn-outline-dark {\r\n  border: 1px solid#222;\r\n}\r\n\r\n.btn-white {\r\n  background: #fff;\r\n  color: #212529;\r\n}\r\n\r\n.btn-trans-white {\r\n  border: 1px solid#fff;\r\n  color: #fff;\r\n  &:hover {\r\n    color: #fff;\r\n    opacity: 0.5;\r\n  }\r\n}\r\n\r\n.btn-outline-dark:hover {\r\n  background: #222 !important;\r\n  color: #fff !important;\r\n}\r\n\r\n.btn.btn-link {\r\n  color: #212529;\r\n}\r\n\r\n.btn:focus {\r\n  box-shadow: none !important;\r\n}\r\n\r\n.btn-circled {\r\n  border-radius: 75px;\r\n}\r\n\r\n.bg-primary,\r\n.btn-primary,\r\n.btn-white:hover {\r\n  background: #21c87a !important;\r\n  border-color: #21c87a !important;\r\n  color: #fff;\r\n}\r\n\r\n.bg-dark,\r\n.btn-primary:hover {\r\n  background: #232323 !important;\r\n  border-color: #232323 !important;\r\n  color: #fff;\r\n}\r\n\r\n.shadow-sm-2 {\r\n  box-shadow: 0 7px 22px rgba(0, 0, 0, 0.08);\r\n}\r\n\r\n/*------------------------\r\n BACKGROUND\r\n----------------------------*/\r\n\r\n.bg-cover {\r\n  background-repeat: no-repeat;\r\n  background-position: 50%;\r\n  background-size: cover;\r\n}\r\n\r\n.bg-cover,\r\n.bg-overlay,\r\n.bg-overlay:before {\r\n  position: absolute;\r\n  top: 0;\r\n  right: 0;\r\n  bottom: 0;\r\n  left: 0;\r\n}\r\n\r\n.bg-overlay:before {\r\n  content: \"\";\r\n  opacity: 0.55;\r\n  background-color: #212529;\r\n}\r\n\r\n.box-shadow {\r\n  box-shadow: 0 25px 100px -5px rgba(0, 0, 0, 0.15);\r\n}\r\n\r\n.mt50 {\r\n  margin-top: 80px;\r\n}\r\n.mt30 {\r\n  margin-top: 30px;\r\n}\r\n\r\n.mb-30 {\r\n  margin-bottom: 30px;\r\n}\r\n\r\n.bg-primary {\r\n  background: $primary-color !important;\r\n}\r\n\r\na {\r\n  color: $primary-color;\r\n  transition: 0.3s;\r\n}\r\n\r\na:hover,\r\na:focus {\r\n  outline: none;\r\n  text-decoration: none;\r\n  color: darken($primary-color, 10);\r\n}\r\n\r\n.disabled-text {\r\n  color: #ffffffcc !important;\r\n  cursor: not-allowed;\r\n}\r\n\r\n.logo {\r\n  width: 100%;\r\n  height: 100%;\r\n}\r\n\r\n.luminous-blend {\r\n  mix-blend-mode: luminosity !important;\r\n}\r\n\r\n.bg-home {\r\n  background: url(\"/images/bg/background.png\");\r\n  background-position: center;\r\n  background-size: cover;\r\n  padding-top: 7rem;\r\n  @media (max-width: 991px) {\r\n    padding-top: 2rem;\r\n  }\r\n}\r\n.seed-section {\r\n  padding: 92px 0;\r\n  @media (max-width: 991px) {\r\n    padding: 48px 0;\r\n  }\r\n}\r\n.bg-home .seed-container {\r\n  max-height: 494px;\r\n  overflow: hidden;\r\n  @media (max-width: 991px) {\r\n    max-height: none;\r\n  }\r\n}\r\n.seed-container {\r\n  padding: 0 80px;\r\n  width: 100%;\r\n  // display: flex;\r\n  @media (max-width: 1400px) {\r\n    padding: 0 72px;\r\n    width: 100%;\r\n  }\r\n  @media (max-width: 1200px) {\r\n    padding: 0 50px;\r\n    width: 100%;\r\n  }\r\n  @media (max-width: 767px) {\r\n    padding: 0 42px;\r\n    width: 100%;\r\n  }\r\n  @media (max-width: 575px) {\r\n    padding: 0px;\r\n    width: 100%;\r\n  }\r\n}\r\n.default-text-black {\r\n  color: $black-text;\r\n  font-size: 16px;\r\n  font-style: normal;\r\n  font-weight: 400;\r\n  line-height: normal;\r\n}\r\n.blogs-slider-prev,\r\n.blogs-slider-next {\r\n  width: 100%;\r\n  height: 100%;\r\n  border: 0px;\r\n  display: flex;\r\n  justify-content: center;\r\n  align-items: center;\r\n  background: transparent;\r\n}\r\n.blogs-slider-prev:focus,\r\n.blogs-slider-next:focus {\r\n  outline: none;\r\n}\r\n.blogs-slider-prev .blog-button-wrapper,\r\n.blogs-slider-next .blog-button-wrapper {\r\n  border: 2px solid #30ab89;\r\n  border-radius: 50px;\r\n  padding: 8px 16px 10px;\r\n  transition: 0.3s ease-in-out;\r\n}\r\n.blogs-slider-prev .blog-button-wrapper img {\r\n  rotate: 180deg;\r\n  transition: 0.3s ease-in-out;\r\n}\r\n.blogs-slider-prev:hover .blog-button-wrapper,\r\n.blogs-slider-next:hover .blog-button-wrapper {\r\n  background-color: #30ab89;\r\n}\r\n.blogs-slider-prev:hover .blog-button-wrapper img,\r\n.blogs-slider-next:hover .blog-button-wrapper img {\r\n  filter: brightness(0) invert(1);\r\n}\r\n.blogs-slider .blog-item {\r\n  height: auto;\r\n  display: flex;\r\n  justify-content: center;\r\n  align-items: center;\r\n  flex-direction: column;\r\n}\r\n.blogs-slider .slick-track {\r\n  display: flex !important;\r\n}\r\n@media (max-width: 991px) {\r\n  .blogs-slider-prev,\r\n  .blogs-slider-next {\r\n    width: auto;\r\n  }\r\n}\r\n","/*----------------------\r\n HEADER STYLE\r\n-----------------------*/\r\n\r\n.header-socials {\r\n  line-height: 22px;\r\n  margin-bottom: 0px;\r\n\r\n  li {\r\n    padding: 8px;\r\n\r\n    a {\r\n      color: #21c87a;\r\n    }\r\n  }\r\n}\r\n\r\n\r\n/*-----------------\r\n LOGO BAR\r\n-------------------*/\r\n\r\n.logo-bar {\r\n  padding: 2px 0px 60px;\r\n}\r\n\r\n.top-info-block {\r\n  margin-right: 30px;\r\n\r\n  h5,\r\n  p {\r\n    margin-bottom: 0px;\r\n  }\r\n}\r\n\r\n\r\n.icon-block {\r\n  margin-right: 20px;\r\n  color: #21c87a;\r\n  font-size: 40px;\r\n  line-height: 20px;\r\n  font-weight: 400;\r\n}\r\n\r\n\r\n.top-info-block:last-child {\r\n  margin-right: 0px;\r\n}\r\n\r\n.header-bar {\r\n  overflow: visible;\r\n  position: relative;\r\n  padding-bottom: 30px;\r\n}\r\n\r\n\r\n.main-navigation {\r\n  margin-top: -40px;\r\n}\r\n\r\n\r\n\r\n\r\n/*-----------------------\r\n HOME-3\r\n---------------------------*/\r\n\r\n.header-white {\r\n  background: #101010;\r\n  -webkit-box-shadow: 0 7px 22px rgba(0, 0, 0, 0.08);\r\n  box-shadow: 0 7px 22px rgba(0, 0, 0, 0.08);\r\n  border-radius: 0px;\r\n}\r\n\r\n.trans-navigation {\r\n  @include desktop {\r\n    background: #101010;\r\n    -webkit-box-shadow: 0 7px 22px rgba(0, 0, 0, 0.08);\r\n    box-shadow: 0 7px 22px rgba(0, 0, 0, 0.08);\r\n    border-radius: 0px;\r\n  }\r\n}\r\n\r\n.trans-navigation .navbar-brand h4,\r\n.site-navigation .navbar-brand h4,\r\n.site-navigation .navbar-brand h3,\r\n.trans-navigation .navbar-brand h3 {\r\n  color: $light;\r\n}\r\n\r\n.banner-content.style-2 {\r\n  padding-top: 200px;\r\n}\r\n\r\n.trans-navigation .navbar-brand {\r\n  padding-top: 13px;\r\n}\r\n\r\n\r\n\r\n.site-navigation.header-white {\r\n  border-bottom: 1px solid transparent;\r\n}\r\n\r\n.site-navigation .navbar-brand {\r\n  padding-top: 13px;\r\n  margin-right: 20px;\r\n}\r\n\r\n\r\n.banner-content2 {\r\n  padding: 200px 0px;\r\n\r\n  .display-4 {\r\n    color: $light;\r\n    font-weight: 600;\r\n  }\r\n\r\n  p.lead {\r\n    color: $light;\r\n  }\r\n}\r\n\r\n\r\n\r\n\r\n\r\n\r\n/* =========================\r\nPRELOADER\r\n=======================*/\r\n\r\n#page-loader {\r\n  background: $light;\r\n  height: 100%;\r\n  width: 100%;\r\n  position: fixed;\r\n  z-index: 9999999;\r\n  // display: none;\r\n}\r\n\r\n.loader-icon {\r\n  background: none repeat scroll 0 0 $light;\r\n  border-bottom: 3px solid rgba(19, 19, 19, 0.1) !important;\r\n  border-left: 3px solid rgba(19, 19, 19, 0.1) !important;\r\n  border-radius: 100px;\r\n  -moz-border-radius: 100px;\r\n  -webkit-border-radius: 100px;\r\n  -o-border-radius: 100px;\r\n  -ms-border-radius: 100px;\r\n  border-right: 3px solid #1453F2 !important;\r\n  border-top: 3px solid rgba(19, 19, 19, 0.1) !important;\r\n  height: 50px;\r\n  left: 50%;\r\n  margin: -20px 0 0 -20px;\r\n  position: absolute;\r\n  text-align: center;\r\n  top: 50%;\r\n  width: 50px;\r\n  -webkit-transform: translate(-50%, -50%);\r\n  -ms-transform: translate(-50%, -50%);\r\n  transform: translate(-50%, -50%);\r\n}\r\n\r\n.colored-border {\r\n  border-color: $light;\r\n}\r\n\r\n.fa-spin {\r\n  -webkit-animation: fa-spin 1s infinite linear;\r\n  animation: fa-spin 1s infinite linear;\r\n}\r\n\r\n@-webkit-keyframes fa-spin {\r\n  0% {\r\n    -webkit-transform: rotate(0deg);\r\n    transform: rotate(0deg);\r\n  }\r\n\r\n  100% {\r\n    -webkit-transform: rotate(359deg);\r\n    transform: rotate(359deg);\r\n  }\r\n}\r\n\r\n@keyframes fa-spin {\r\n  0% {\r\n    -webkit-transform: rotate(0deg);\r\n    transform: rotate(0deg);\r\n  }\r\n\r\n  100% {\r\n    -webkit-transform: rotate(359deg);\r\n    transform: rotate(359deg);\r\n  }\r\n}\r\n",".service-banner {\r\n    height: 400px;\r\n    background: url(/images/services-page/ai-services/banner-bg.png);\r\n    background-repeat: no-repeat;\r\n    background-position: right;\r\n    padding: 80px 80px 80px;\r\n    position: relative;\r\n    @media(max-width:1200px) {\r\n        padding: 80px 46px 80px;\r\n    }\r\n    @media(max-width:991px) {\r\n        padding: 60px 46px 60px;\r\n        height: auto;\r\n    }\r\n}\r\n.service-banner::after {\r\n    position: absolute;\r\n    left: 0;\r\n    top: 0;\r\n    width: 100%;\r\n    height: 100%;\r\n    content: \"\";\r\n    z-index: -1;\r\n    background: linear-gradient(180deg, #101010 0%, #061511 100%);\r\n}\r\n.service-banner .path {\r\n  gap: 10px;\r\n  position: absolute;\r\n}\r\n.service-banner-content {\r\n  padding: 72px 0;\r\n}\r\n.service-banner-content .left-container p {\r\n    line-height: normal;\r\n}\r\n.service-banner-content h1 {\r\n    font-size: 48px;\r\n    font-style: normal;\r\n    font-weight: 700;\r\n    line-height: normal;\r\n    color: #FAFAFA;\r\n    margin-bottom: 20px !important;\r\n    @media(max-width:1200px) {\r\n        font-size: 42px;\r\n    }\r\n}\r\n.service-banner-content h1 span {\r\n    color: #30AB89;\r\n}\r\n.service-banner-content .right-container {\r\n    max-width: 450px;\r\n    @media(max-width:1200px) {\r\n        max-width: 45%;\r\n    }\r\n}","\r\n\r\n/*--------------------------\r\nPAGE BANNER\r\n--------------------------*/\r\n\r\n.page-banner-area{\r\n    padding: 180px 0px;\r\n}\r\n.page-contact{\r\n    position: relative;\r\n    padding: 180px 0px;\r\n    background: url(\"../images/banner/p-6.jpg\")fixed 50% 50% no-repeat;\r\n    -webkit-background-size: cover;\r\n    background-size:cover ;\r\n}\r\n.page-service{\r\n    position: relative;\r\n    padding: 180px 0px;\r\n    background: url(\"../images/banner/service.jpg\")fixed 50% 50% no-repeat;\r\n    -webkit-background-size: cover;\r\n    background-size:cover ;\r\n}\r\n\r\n.page-about{\r\n    position: relative;\r\n    padding: 180px 0px;\r\n    background: url(\"../images/banner/about.jpg\")fixed 50% 50% no-repeat;\r\n    -webkit-background-size: cover;\r\n    background-size:cover ;\r\n}\r\n\r\n.page-pricing{\r\n    position: relative;\r\n    padding: 180px 0px;\r\n    background: url(\"../images/banner/img2.jpg\")fixed 50% 50% no-repeat;\r\n    -webkit-background-size: cover;\r\n    background-size:cover ;\r\n}\r\n\r\n.page-project{\r\n    position: relative;\r\n    padding: 180px 0px;\r\n    background: url(\"../images/banner/p-4.jpg\")fixed 50% 50% no-repeat;\r\n    -webkit-background-size: cover;\r\n    background-size:cover ;\r\n}\r\n\r\n\r\n.page-banner-content h1{\r\n    color: $light;\r\n}\r\n.page-banner-content p{\r\n    color: $border-color;\r\n}\r\n\r\n.form-control{\r\n    border-radius: 0px;\r\n    height: 45px;\r\n}\r\n","/*-------------------\r\n   MENU\r\n----------------------*/\r\n.navbar-toggler-icon {\r\n  display: inline-block;\r\n  width: 1.5em;\r\n  height: 1.5em;\r\n  content: \"\";\r\n  vertical-align: middle;\r\n  background: no-repeat 50%;\r\n  background-size: 100% 100%\r\n}\r\n\r\n.navbar-dark .navbar-toggler {\r\n  color: #fff;\r\n  border-color: rgba(255,255,255,.1);\r\n  padding: 10px 12px;\r\n  &:focus {\r\n    outline: 0;\r\n  }\r\n}\r\n\r\n.main-nav {\r\n  margin-bottom: -45px;\r\n  z-index: 999;\r\n}\r\n\r\n.navbar-nav .nav-link {\r\n  padding-right: 1rem !important;\r\n  padding-left: 1rem !important;\r\n  transition: .3s;\r\n}\r\n\r\n.navbar-dark .navbar-nav .nav-link {\r\n  color: $light;\r\n  font-weight: 500;\r\n  letter-spacing: .5px;\r\n  // text-transform: uppercase;\r\n}\r\n\r\n.rounded-radius {\r\n  border-radius: 5px;\r\n}\r\n\r\n.navbar {\r\n  position: relative;\r\n  padding: 1rem 0rem;\r\n\r\n\r\n  &:before {\r\n    position: absolute;\r\n    z-index: -1;\r\n    top: 0;\r\n    right: 0;\r\n    bottom: 0;\r\n    left: 0;\r\n    content: \"\";\r\n    transition: opacity .15s linear;\r\n    opacity: 0;\r\n    border-bottom: 1px solid rgba(0, 0, 0, .1);\r\n    background-color: $light;\r\n\r\n  }\r\n}\r\n\r\n.dropdown-toggle::after {\r\n  margin-left: .255em;\r\n  vertical-align: 1px;\r\n  content: \"\\f078\";\r\n  border: 0;\r\n  font-family: \"Font Awesome 5 Free\";\r\n  font-size: 12px;\r\n}\r\n\r\n.fixed-top {\r\n  position: fixed;\r\n  z-index: 1030;\r\n  right: 0;\r\n  left: 0;\r\n}\r\n\r\n\r\n.navbar-dark {\r\n  color: $light;\r\n}\r\n\r\n\r\n.navbar-light {\r\n  color: $black;\r\n\r\n  &:before {\r\n    opacity: 1;\r\n  }\r\n}\r\n\r\n\r\n.navbar .nav-item-divider {\r\n  display: none;\r\n\r\n  .nav-link {\r\n    opacity: .25;\r\n  }\r\n}\r\n\r\n.header-bar.fixed-header .main-navigation {\r\n  position: fixed;\r\n  left: 0;\r\n  top: 0;\r\n  width: 100%;\r\n  background: #101010;\r\n  border-color: transparent;\r\n\r\n}\r\n\r\n.primary-btn {\r\n  padding: 0.5rem 1.25rem; border-radius: 2rem; background-color: #30ab89;\r\n  font-weight: 500;\r\n  color: #fff;\r\nfont-size: 1rem;\r\n  .nav-link {\r\n    padding: 0;\r\n    font-weight: 500;\r\n  }\r\n}\r\n\r\n\r\n.primary-btn:hover, .primary-btn:visited{\r\n  color: #fff;\r\n}\r\n/*-------------------\r\n  DROPDOWN MENU\r\n----------------------*/\r\n.has-dropdown {\r\n  .dropdown-menu {\r\n    border: none;\r\n    box-shadow: 0 0 25px 0 rgba(0, 0, 0, 0.08);\r\n    padding: 0;\r\n    margin: 0;\r\n\r\n    @include desktop {\r\n      text-align: center;\r\n      float: left !important;\r\n      width: 100%;\r\n      margin: 0;\r\n    }\r\n\r\n    a {\r\n      font-weight: normal;\r\n      color: #808080;\r\n      padding: 10px 20px;\r\n      @include transition (all, 0.3s, ease);\r\n      border-bottom: 1px solid #eee;\r\n      border-radius: 4px;\r\n\r\n      &:focus,\r\n      &:hover {\r\n        background: $primary-color;\r\n\r\n        color: $light;\r\n      }\r\n    }\r\n  }\r\n}\r\n\r\n.dropleft .dropdown-menu,\r\n.dropright .dropdown-menu {\r\n  margin: 0;\r\n}\r\n\r\n.dropleft .dropdown-toggle::before,\r\n.dropright .dropdown-toggle::after {\r\n  font-weight: bold;\r\n  font-family: \"Font Awesome 5 Free\";\r\n  border: 0;\r\n  font-size: 10px;\r\n  vertical-align: 1px;\r\n}\r\n\r\n.dropleft .dropdown-toggle::before {\r\n  content: \"\\f053\";\r\n  margin-right: 7px;\r\n}\r\n\r\n.dropright .dropdown-toggle::after {\r\n  content: \"\\f054\";\r\n  margin-left: 7px;\r\n}\r\n\r\n.dropdown-item {\r\n  padding: .6rem 1.4rem;\r\n  text-transform: uppercase;\r\n  font-size: 12px;\r\n  font-weight: 700;\r\n}\r\n\r\n.dropdown-submenu:hover>.dropdown-item,\r\n.dropdown-item:hover {\r\n  background: #101010;\r\n  color: $light !important;\r\n}\r\n\r\n.dropdown-item.active {\r\n  text-decoration: underline;\r\n  background-color: transparent;\r\n  color: inherit;\r\n}\r\n.dropdown-submenu.active>.dropdown-toggle {\r\n  text-decoration: underline;\r\n  color: inherit;\r\n}\r\n\r\nul.dropdown-menu li {\r\n  padding-left: 0px !important;\r\n}\r\n\r\n@media (min-width:992px) {\r\n  .dropdown-menu {\r\n    transition: all .2s ease-in, visibility 0s linear .2s, transform .2s linear;\r\n    display: block;\r\n    visibility: hidden;\r\n    opacity: 0;\r\n    min-width: 200px;\r\n    transform: translateY(15px);\r\n  }\r\n\r\n  .dropdown:hover>.dropdown-menu {\r\n    visibility: visible;\r\n    transition: all .35s ease 0s;\r\n    opacity: 1;\r\n    transform: translateY(0);\r\n  }\r\n}\r\n\r\n.pt-60px{\r\n  padding-top: 60px !important;\r\n}\r\n@media (max-width:992px) {\r\n  .position-md-sticky {\r\n    position: sticky !important;\r\n  }\r\n}","// Transition\r\n@mixin transition($what: all, $time: 0.2s, $how: ease-in-out) {\r\n    -webkit-transition: $what $time $how;\r\n    -moz-transition:    $what $time $how;\r\n    -ms-transition:     $what $time $how;\r\n    -o-transition:      $what $time $how;\r\n    transition:         $what $time $how;\r\n}\r\n\r\n// Transform\r\n@mixin transform($transforms) {\r\n\t   -moz-transform: $transforms;\r\n\t     -o-transform: $transforms;\r\n\t    -ms-transform: $transforms;\r\n\t-webkit-transform: $transforms;\r\n          transform: $transforms;\r\n}\r\n// rotate\r\n@mixin rotate ($deg) {\r\n  @include transform(rotate(#{$deg}deg));\r\n}\r\n \r\n// scale\r\n@mixin scale($scale) {\r\n\t @include transform(scale($scale));\r\n} \r\n// translate\r\n@mixin translate ($x, $y) {\r\n   @include transform(translate($x, $y));\r\n}\r\n// skew\r\n@mixin skew ($x, $y) {\r\n   @include transform(skew(#{$x}deg, #{$y}deg));\r\n}\r\n//transform origin\r\n@mixin transform-origin ($origin) {\r\n    moz-transform-origin: $origin;\r\n\t     -o-transform-origin: $origin;\r\n\t    -ms-transform-origin: $origin;\r\n\t-webkit-transform-origin: $origin;\r\n          transform-origin: $origin;\r\n}","/*----------------------\r\n BANNER STYLE\r\n-----------------------*/\r\n\r\n.py-7 {\r\n  padding: 7.5rem 0;\r\n}\r\n\r\n.py-4 {\r\n  padding: 4.5rem 0;\r\n}\r\n\r\n.py-8 {\r\n  padding: 8.5rem 0;\r\n}\r\n\r\n.main-banner {\r\n  h5 {\r\n    margin-bottom: 20px;\r\n  }\r\n  h1.display-4 {\r\n    line-height: 65px;\r\n  }\r\n}\r\n\r\n.main-banner p.lead,\r\n.banner-content p.lead {\r\n  margin-bottom: 2.5rem !important;\r\n}\r\n\r\n/*-------------------------\r\n HOME -2\r\n-----------------------------*/\r\n#banner {\r\n  position: relative;\r\n  background: url(\"/images/bg/banner_bg.jpg\") no-repeat;\r\n  -webkit-background-size: cover;\r\n  background-size: cover;\r\n}\r\n\r\n.banner-content {\r\n  padding: 150px 0px;\r\n  padding-right: 30px;\r\n  p {\r\n    color: $border-color;\r\n    padding-right: 80px;\r\n    margin-bottom: 30px !important;\r\n  }\r\n  .display-4 {\r\n    color: $light;\r\n    font-weight: 600;\r\n  }\r\n}\r\n\r\n#banner .overlay {\r\n  opacity: 0.7;\r\n}\r\n\r\n.banner-contact-form {\r\n  padding: 45px 40px;\r\n  margin-top: 30px;\r\n\r\n  .form-control {\r\n    border-radius: 0px;\r\n    height: 45px;\r\n  }\r\n\r\n  textarea.form-control {\r\n    height: auto;\r\n  }\r\n}\r\n\r\n.transform-y-10 {\r\n  transform: translateY(2%);\r\n}\r\n\r\n.slick-dots {\r\n  position: absolute;\r\n  bottom: 45%;\r\n  left: -32px;\r\n  @media (max-width: 1400px) {\r\n  left: -40px;\r\n  }\r\n  @media (max-width: 1200px) {\r\n  left: -35px;\r\n  }\r\n  @include desktop {\r\n    bottom: 90%;\r\n    left: auto;\r\n  }\r\n  @include tablet-xs {\r\n    bottom: 95%;\r\n  }\r\n  // @include mobile {\r\n  //   bottom: 95%;\r\n  // }\r\n  @include tablet {\r\n    bottom: 90%;\r\n    padding-left: 0;\r\n  }\r\n}\r\n.slick-dots li {\r\n  // display: block;\r\n  margin-top: 10px;\r\n  @media (min-width: 992px) {\r\n    display: block;\r\n  }\r\n}\r\n\r\n.slick-dots li svg:nth-child(1) {\r\n  display: block;\r\n}\r\n\r\n.slick-dots li svg:nth-child(2) {\r\n  display: none;\r\n}\r\n\r\n.slick-dots li.slick-active svg:nth-child(1) {\r\n  display: none;\r\n}\r\n\r\n.slick-dots li.slick-active svg:nth-child(2) {\r\n  display: block;\r\n}\r\n.slick-carousel {\r\n  height: auto;\r\n}\r\n\r\n//.slider-container{\r\n//  display: flex;\r\n//  justify-content: space-between;\r\n//  align-items: center;\r\n//  position: relative;\r\n//  width: 100%;\r\n//  text-align: left;\r\n//  @include large-desktop{\r\n//    height: 50vh;\r\n//  }\r\n//  @include desktop{\r\n//    height: 60vh;\r\n//  }\r\n//  @include tablet{\r\n//    text-align: center;\r\n//    margin-top: 60px;\r\n//  }\r\n//  @include mobile{\r\n//    flex-direction: column;\r\n//    justify-content: center;\r\n//    margin-top: 80px;\r\n//    height: auto;\r\n//  }\r\n//  @include tablet-xs{\r\n//    flex-direction: column;\r\n//    justify-content: center;\r\n//    margin-top: 50px;\r\n//    height: auto;\r\n//  }\r\n//\r\n//\r\n//}\r\n//\r\n//.slider-typo{\r\n//  @media (min-width: 1201px) and (max-width:2000px) {\r\n//    width: 55%;\r\n//    //position: absolute;\r\n//    margin-top:12%;\r\n//  }\r\n//  @include large-desktop{\r\n//    position: absolute;\r\n//    left: 2%;\r\n//    top: 30%;\r\n//    width: 70%;\r\n//  }\r\n//  @include desktop{\r\n//    width: 100%;\r\n//    position: absolute;\r\n//    top: 10vh;\r\n//    left: -3vw;\r\n//  }\r\n//  @include tablet{\r\n//    position: absolute;\r\n//    top: -4%;\r\n//    left: 2%;\r\n//    width: 100%;\r\n//    transform: translateX(0);\r\n//    font-size: 50px;\r\n//  }\r\n//  @include tablet-xs{\r\n//    position: static;\r\n//    width: 100%;\r\n//  }\r\n//  @include mobile{\r\n//    position: static;\r\n//    width: 100%;\r\n//  }\r\n//\r\n//\r\n//}\r\n//\r\n//\r\n//.slider-img{\r\n//\r\n//  @media (min-width: 1201px) and (max-width:2000px) {\r\n//   position: absolute;\r\n//    right: -5%;\r\n//    bottom:-27vh;\r\n//  }\r\n//  @media (min-width: 1300px) and (max-width:1600px) {\r\n//    position: absolute;\r\n//    right: -5%;\r\n//    bottom:-30vh;\r\n//  }\r\n//  @include large-desktop{\r\n//    position: absolute;\r\n//    top: 10%;\r\n//    right: -5%;\r\n//  }\r\n//  @include desktop{\r\n//    position: absolute;\r\n//    right: -20vw;\r\n//    top:15vh;\r\n//  }\r\n//  @include tablet{\r\n//    //position: absolute;\r\n//    //right: -2vw;\r\n//    //top: 20vh;\r\n//    position: static;\r\n//    transform: translate(-8%,30%);\r\n//  }\r\n//  @include tablet-xs{\r\n//    //position: absolute;\r\n//    //right: -1vw;\r\n//    //top: 20vh;\r\n//    position: static;\r\n//    transform: translateX(-5%);\r\n//  }\r\n//\r\n//  @include mobile{\r\n//    position: static;\r\n//    transform: translateX(-5%);\r\n//  }\r\n//\r\n//}\r\n//\r\n\r\n//.container{\r\n//  position: relative;\r\n//  height: 60vh;\r\n//}\r\n\r\n.slick-carousel {\r\n  width: 100%;\r\n}\r\n.text-primary{\r\n  color: #30AB89 !important;\r\n}\r\n// .slider-container h1 {\r\n  // @include desktop {\r\n  //   font-size: 20px;\r\n  // }\r\n// }\r\n\r\n.slider-container {\r\n  z-index: 10000;\r\n  position: relative;\r\n  width: 100%;\r\n  display: flex;\r\n  flex-direction: row;\r\n  align-items: center;\r\n  justify-content: space-between;\r\n  // padding: 20px;\r\n  box-sizing: border-box;\r\n  height: fit-content;\r\n  @include desktop {\r\n    padding: 0 20px;\r\n    flex-direction: column;\r\n    justify-content: center;\r\n    align-items: center;\r\n    height: 69vh;\r\n  }\r\n\r\n  .text-primary {\r\n    background: none;\r\n  }\r\n\r\n  // @include mobile {\r\n  //   height: 70vh;\r\n  // }\r\n}\r\n.slider-typo {\r\n  flex: 1;\r\n  width: 100%;\r\n  display: flex;\r\n  max-width: 800px;\r\n  // align-items: center;\r\n  // height: 69vh;\r\n  @include desktop {\r\n    text-align: center;\r\n    justify-content: center;\r\n  }\r\n}\r\n.img-cont {\r\n  display: flex;\r\n  justify-content: flex-end;\r\n  align-items: flex-end;\r\n  margin-top: auto;\r\n\r\n  @include tablet {\r\n    justify-content: center;\r\n  }\r\n}\r\n#plantImg{\r\n  filter: grayscale(100%);\r\n}\r\n.slider-img {\r\n  width: 100%;\r\n  height: auto;\r\n  transform: translateY(5%);\r\n  filter: grayscale(100%);\r\n\r\n  img {\r\n    width: 100%;\r\n  }\r\n}\r\n\r\nsection.slick-dotted.slick-slider {\r\n  margin-bottom: 0;\r\n}\r\n\r\n@media (min-width: 992px) {\r\n  .carousel-cont {\r\n    padding-left: 10px;\r\n  }\r\n\r\n  .slider-img {\r\n    margin-right: 2rem;\r\n  }\r\n}\r\n@media (min-width: 768px) and (max-width: 992px) {\r\n  .slider-typo {\r\n    margin-top: 120px;\r\n  }\r\n  .slider-container {\r\n    height: 75vh;\r\n  }\r\n  .slider-img {\r\n    margin-right: 1rem;\r\n  }\r\n}\r\n\r\n@media (max-width: 1000px) {\r\n  .slider-typo {\r\n    margin-top: 100px;\r\n  }\r\n}\r\n\r\n\r\n","\r\n#banner-3{\r\n    position: relative;\r\n    background: url(\"../images/banner/banner.jpg\")no-repeat;\r\n    -webkit-background-size: cover;\r\n    background-size: cover;\r\n}\r\n\r\n#banner-4{\r\n    position: relative;\r\n    background: url(\"../images/banner/banner-2.jpg\")no-repeat;\r\n    -webkit-background-size: cover;\r\n    background-size: cover;\r\n}\r\n\r\n",".seed-stats {\r\n  background: url(../../images/stats/stats-bg.png);\r\n  background-size: cover;\r\n  background-position: center;\r\n  background-repeat: no-repeat;\r\n}\r\n.default-section-heading {\r\n  color: $black-text;\r\n  font-size: 32px;\r\n  font-weight: 600;\r\n}\r\n.default-section-heading span {\r\n  color: $primary-colors;\r\n}\r\n.default-text-para {\r\n  color: $black-text;\r\n  font-style: normal;\r\n  line-height: normal;\r\n}\r\n.seed-stats .stats-count .count {\r\n  color: $black-text;\r\n  font-size: 44px;\r\n  font-weight: 800;\r\n  @media (max-width:767px) {\r\n    font-size: 32px;\r\n  }\r\n}\r\n.seed-stats .stats-count p {\r\n  color: $black-text;\r\n  font-size: 12px;\r\n  font-weight: 500;\r\n}\r\n","\r\n/*----------------------\r\n FEATURE STYLE\r\n-----------------------*/\r\n.img-icon-block {\r\n    position: relative;\r\n\r\n    &:before {\r\n        position: absolute;\r\n        content: \"\";\r\n        top: -2rem;\r\n        background: #A5EBD7;\r\n        opacity: 1;\r\n        width: 84px;\r\n        left: 5rem;\r\n        height: 84px;\r\n        border-radius: 50%;\r\n        z-index: 1;\r\n    }\r\n\r\n    img{\r\n        font-size: 58px;\r\n        z-index: 3!important;\r\n        color: #333;\r\n        position: relative;\r\n        width: 48px;\r\n        height: 48px;\r\n    }\r\n}\r\n\r\n/*--------------------------\r\nABOUT-2\r\n---------------------------*/\r\n#about .img-block{\r\n    position: relative;\r\n      -webkit-box-shadow: 0 7px 22px rgba(0, 0, 0, 0.08);\r\n    box-shadow: 0 7px 22px rgba(0, 0, 0, 0.08);\r\n\r\n    img{\r\n        border: 5px solid $primary-color;\r\n    }\r\n}\r\n.pt-6{\r\n    padding-top: 4.5rem;\r\n}\r\n.img-icon i{\r\n    font-size: 60px;\r\n}\r\n#feature .head-title-text {\r\n    color: var(--text-color, #2C2C2C);\r\n    text-align: center;\r\n    font-family: Plus Jakarta Sans;\r\n    font-size: 20px;\r\n    font-style: normal;\r\n    font-weight: 500;\r\n    line-height: normal;\r\n    max-width: 600px;\r\n    display: inline-block;\r\n}\r\n#feature .head-title-text span {\r\n    color: #30AB89;\r\n    font-weight: 700;\r\n}\r\n@media screen and (max-width: 991px) {\r\n.img-icon-block {\r\n        &:before {\r\n            width: 70px;\r\n            height: 70px;\r\n        }\r\n        img {\r\n            width: 50px;\r\n            height: 50px;\r\n        }\r\n    }\r\n    #feature .head-title-text {\r\n        font-size: 20px;\r\n    }\r\n}","/*----------------------\r\n SERVICE\r\n-----------------------*/\r\n\r\n.service-container {\r\n  margin: auto;\r\n  max-width: 1540px;\r\n  \r\n  margin: 80px auto;\r\n\r\n  @media (max-width: 1154px) {\r\n    margin: 50px auto;\r\n  }\r\n}\r\n\r\nh5.subtitle {\r\n  color: $primary-color;\r\n  margin-bottom: 10px;\r\n  font-weight: 300;\r\n}\r\n\r\n#service-subheading {\r\n  color: $black-text;\r\n  text-align: center;\r\n  font-size: 16px;\r\n  font-style: normal;\r\n  font-weight: 400;\r\n  line-height: 1.5;\r\n\r\n  @media (max-width: 1154px) {\r\n    font-size: 14px;\r\n  }\r\n}\r\n\r\n#service-heading {\r\n  margin-bottom: 14px !important;\r\n  font-size: 32px;\r\n  line-height: 1.25;\r\n  @media (max-width: 1154px) {\r\n    font-size: 25px;\r\n  }\r\n  span {\r\n    color: #30AB89;\r\n  }\r\n}\r\n\r\n.service-heading {\r\n  margin-bottom: 50px !important;\r\n}\r\n\r\n.service-images {\r\n  margin-bottom: -200px;\r\n  border: 10px solid $light;\r\n}\r\n\r\n.service-content {\r\n  padding-top: 60px;\r\n  padding-left: 15px;\r\n\r\n  h1 {\r\n    margin-bottom: 20px;\r\n    margin-top: 15px;\r\n  }\r\n}\r\n\r\n.service-icon {\r\n  margin-right: 20px;\r\n  color: $light;\r\n  font-size: 25px;\r\n  width: 50px;\r\n  height: 50px;\r\n  background: #A5EBD7;\r\n  text-align: center;\r\n  border-radius: 50%;\r\n  padding-top: 5px;\r\n}\r\n\r\n.service-block {\r\n  margin-bottom: 50px;\r\n}\r\n\r\n.service-inner-content h4 {\r\n  // text-transform: uppercase;\r\n}\r\n\r\n/*----------------------\r\n WEB SERVICES\r\n-----------------------*/\r\n#services-2{\r\n  position: relative;\r\n  padding: 20px;\r\n  -webkit-background-size: cover;\r\n  background-size: cover;\r\n  background-color: #FAFAFA;\r\n  color: $black-text;\r\n}\r\n\r\n.service-blocks {\r\n  display: grid;\r\n  grid-template-columns: 1fr 1fr 1fr;\r\n  gap: 30px;\r\n\r\n  @media (max-width: 1154px) {\r\n    grid-template-columns: 1fr 1fr;\r\n  }\r\n\r\n  @media (max-width: 800px) {\r\n    grid-template-columns: 1fr;\r\n  }\r\n}\r\n\r\n// .web-service-block:hover {\r\n//   border: 1px solid #2b9778;\r\n// }\r\n.web-service-block {\r\n  display: flex;\r\n  flex-direction: column;\r\n  gap: 1rem;\r\n  padding: 1.5rem;\r\n  transition: 0.3s;\r\n  border-radius: 5px;\r\n  // border: 1px solid #fff;\r\n  cursor: pointer;\r\n\r\n  .image-container {\r\n    height: 4rem;\r\n  }\r\n  .image-container img {\r\n    height: 100%;\r\n  filter: brightness(1) invert(1);\r\n  }\r\n\r\n  h3 {\r\n    font-size: 25px;\r\n    margin: 0;\r\n    transition: 0.3s;\r\n    color: $black-text;\r\n  }\r\n\r\n\r\n  p {\r\n    font-size: 15px;\r\n    font-weight: 400;\r\n    transition: 0.3s;\r\n    color: $black-text;\r\n    line-height: 1.5;\r\n    \r\n  }\r\n\r\n  a {\r\n    color: #30AB89 !important;\r\n    font-size: 18px;\r\n    font-weight: 700;\r\n    cursor: pointer;\r\n    margin-top: auto;\r\n  }\r\n}\r\n\r\n.service-img {\r\n  margin-bottom: -200px !important;\r\n  border: 10px solid $light;\r\n  margin: auto;\r\n}\r\n","/*----------------------\r\n PRoject\r\n-----------------------*/\r\n#projects-wrap {\r\n  position: relative;\r\n  background: url(\"../images/bg/banner_bg.jpg\") no-repeat;\r\n  -webkit-background-size: cover;\r\n  background-size: cover;\r\n\r\n  p.lead {\r\n    color: #a9a9a9 !important;\r\n  }\r\n}\r\n\r\n.overlay {\r\n  position: absolute;\r\n  left: 0;\r\n  top: 0;\r\n  width: 100%;\r\n  height: 100%;\r\n  background: rgba(0, 0, 0, 0.92);\r\n}\r\n\r\n.overlay.feature-overlay {\r\n  background-image: linear-gradient(\r\n    30deg,\r\n    rgba(121, 110, 255, 0.95) 0%,\r\n    #30ab89 100%\r\n  );\r\n  opacity: 0.9;\r\n}\r\n\r\n#projects {\r\n  margin-top: -60px;\r\n}\r\n\r\n.single-project img {\r\n  border-radius: 10px;\r\n}\r\n\r\n.project-content {\r\n  text-align: center;\r\n  padding: 40px 20px;\r\n  position: relative;\r\n  .btn {\r\n    padding: 0.7rem 1.7rem;\r\n    border-radius: 25px;\r\n  }\r\n  p {\r\n    margin-top: 20px;\r\n  }\r\n  h4 {\r\n    text-transform: capitalize;\r\n  }\r\n}\r\n\r\n.project-content-block {\r\n  padding: 70px 40px;\r\n  margin-left: -120px;\r\n  background: #f4f7fc;\r\n  position: absolute;\r\n  bottom: -70px;\r\n  border: 15px solid $light;\r\n  -webkit-box-shadow: 0 7px 22px rgba(0, 0, 0, 0.08);\r\n  box-shadow: 0 7px 22px rgba(0, 0, 0, 0.08);\r\n  h4 {\r\n    color: $primary-color;\r\n  }\r\n  p {\r\n    margin-top: 25px;\r\n  }\r\n}\r\n\r\n/*-------------------------\r\n PORTFOLIO-2\r\n---------------------------*/\r\n\r\n.single-work {\r\n  -webkit-transition: all 300ms ease-in-out;\r\n  -o-transition: all 300ms ease-in-out;\r\n  transition: all 300ms ease-in-out;\r\n}\r\n\r\n.overlay-content-block {\r\n  position: absolute;\r\n  content: \"\";\r\n  bottom: 20px;\r\n  width: 100%;\r\n  left: 30px;\r\n  padding: 30px 20px;\r\n  background: $light;\r\n  opacity: 0;\r\n  visibility: hidden;\r\n  -webkit-transition: all 300ms ease-in-out;\r\n  -o-transition: all 300ms ease-in-out;\r\n  transition: all 300ms ease-in-out;\r\n  border-radius: 5px 0px 0px 5px;\r\n\r\n  .icon {\r\n    width: 50px;\r\n    height: 50px;\r\n    display: inline-block;\r\n    text-align: center;\r\n    padding-top: 12px;\r\n    border-radius: 100%;\r\n    position: absolute;\r\n    left: 30px;\r\n    top: -23px;\r\n    background: $primary-color;\r\n    color: $light;\r\n  }\r\n\r\n  h4 {\r\n    margin-bottom: 0px;\r\n    margin-top: 10px;\r\n  }\r\n}\r\n\r\n.work-block {\r\n  position: relative;\r\n  border: 5px solid $light;\r\n\r\n  img {\r\n    width: 100%;\r\n    border-radius: 10px;\r\n    box-shadow: 0px 2px 10px 0px rgba(0, 0, 0, 0.14);\r\n    object-fit: cover;\r\n    aspect-ratio: 4/3;\r\n  }\r\n\r\n  &:hover .overlay-content-block {\r\n    opacity: 1;\r\n    visibility: visible;\r\n  }\r\n\r\n}\r\n\r\n.card-content {\r\n  padding: 0.7rem 0.5rem 0;\r\n\r\n  h4 {\r\n    color: var(--text-color, #2C2C2C);\r\n    font-size: 24px;\r\n    font-style: normal;\r\n    font-weight: 600;\r\n    line-height: normal;\r\n  }\r\n  p {\r\n    color: var(--text-color, #2C2C2C);\r\nfont-size: 14px;\r\nfont-style: normal;\r\nfont-weight: 400;\r\nline-height: normal;\r\n  }\r\n  .link {\r\n    font-weight: 600;\r\n    color: #30AB89\r\n  }\r\n}\r\n\r\n/* ==============================\r\n  SINGEL PROJECTS\r\n=============================*/\r\n\r\n.project-details-info {\r\n  margin: 40px 0px;\r\n}\r\n\r\n.info-block-2 {\r\n  float: left;\r\n  margin-right: 65px;\r\n  margin-bottom: 40px;\r\n}\r\n\r\n.project-info ul {\r\n  margin-top: 40px;\r\n  li {\r\n    margin-bottom: 30px;\r\n    padding-right: 20px;\r\n  }\r\n}\r\n\r\n.project-lg-images img {\r\n  width: 100%;\r\n}\r\n\r\n.alumni-description {\r\n  color: var(--text-color, #2c2c2c);\r\n  text-align: center;\r\n  font-size: 20px;\r\n  font-style: normal;\r\n  font-weight: 500;\r\n  line-height: normal;\r\n  span {\r\n    color: #30ab89;\r\n    font-weight: 700;\r\n  }\r\n  color: #343a40;\r\n}\r\n","/*----------------------\r\n PROCESS\r\n-----------------------*/\r\nsection#process {\r\n  background-image: url(\"../../images/bg/Logo seed.png\");\r\n  background-repeat: no-repeat;\r\n  background-size: contain;\r\n  background-position: left;\r\n  min-height: 574px;\r\n  // background-position: 84%;\r\n}\r\n#alumni-container {\r\n  img {\r\n    filter: none;\r\n    margin: 30px auto;\r\n    display: flex;\r\n    justify-content: center;\r\n    align-items: center;\r\n  }\r\n  p {\r\n    font-size: 18px;\r\n    margin: auto;\r\n    font-family: \"Plus Jakarta Sans\", sans-serif !important;\r\n  }\r\n  @media screen and (max-width: 991px) {\r\n    p {\r\n      font-size: 24px !important;\r\n    }\r\n  }\r\n  @media screen and (max-width: 767px) {\r\n    p {\r\n      font-size: 18px !important;\r\n    }\r\n  }\r\n  @media screen and (max-width: 575px) {\r\n    p {\r\n      font-size: 16px !important;\r\n    }\r\n  }\r\n}\r\n#bytecorpimg {\r\n  width: 45px;\r\n}\r\n#Foliologo {\r\n  width: 150px;\r\n}\r\n#nustlogo {\r\n  width: 170px;\r\n}\r\n#JafferLogo {\r\n  width: 120px;\r\n}\r\n\r\n.process-block {\r\n  margin: auto;\r\n  text-align: center;\r\n  img {\r\n    border-radius: 5px;\r\n    margin-bottom: 45px;\r\n    // fil