  width: 50%;\r\n        margin: 10px auto;\r\n\r\n    }\r\n}\r\n\r\n\r\n\r\n.price-features {\r\n    margin: 30px 0px 50px;\r\n    li {\r\n        font-size: 16px;\r\n        padding: 5px 0px;\r\n        position: relative;\r\n        padding-left: 30px;\r\n\r\n        &:before{\r\n            position: absolute;\r\n            content:\"\\f00c\";\r\n            font-family: \"Font Awesome 5 Free\";\r\n            left: 0px;\r\n            top: 5px;\r\n            color: $primary-color;\r\n            font-weight: 900;\r\n        }\r\n    }\r\n}\r\n\r\n\r\n\r\n.pricing-block .price-features li{\r\n    padding-left: 0px;\r\n    &:before{\r\n        display: none;\r\n    }\r\n}\r\n\r\n\r\n\r\n/*--------------------------\r\nPRICING-2\r\n---------------------------*/\r\n.pricing-box{\r\n    border: 1px solid $border-color;\r\n    padding: 60px;\r\n    -webkit-transition: all 300ms ease-in-out;\r\n    -o-transition:all 300ms ease-in-out ;\r\n    transition:all 300ms ease-in-out ;\r\n\r\n    .price-block h2 span{\r\n        font-size: 12px;\r\n        font-weight: normal;\r\n        text-transform: capitalize;\r\n    }\r\n    &:hover{\r\n        background: rgb(29, 28, 28);\r\n        border-color: rgb(29, 28, 28);\r\n    }\r\n\r\n    &:hover .price-features li{\r\n        color: $border-color;\r\n    }\r\n    &:hover .price-block h2{\r\n        color: $light;\r\n    }\r\n    &:hover h3{\r\n        color: $light;\r\n    }\r\n    &:hover .btn{\r\n        background: $light!important;\r\n        color: #000!important;\r\n    }\r\n\r\n}\r\n\r\n","/*----------------------\r\n BLOG SECTION\r\n-----------------------*/\r\n.blog-box {\r\n  position: relative;\r\n  display: flex;\r\n  flex-direction: column;\r\n    align-items: center;\r\n    height: 100%;\r\n\r\n  .blog-img-box img {\r\n    width: 100%;\r\n    border-radius: 10px;\r\n    box-shadow: 0px 2px 10px 0px rgba(0, 0, 0, 0.14);\r\n    object-fit: contain;\r\n    aspect-ratio: 16/11;\r\n    background-color: #101010;\r\n  }\r\n}\r\n\r\n.single-blog {\r\n  padding-top: 25px;\r\n  position: relative;\r\n  height: 100%;\r\n}\r\n\r\n.bg-light .single-blog {\r\n  padding: 40px;\r\n  text-align: center;\r\n  border-bottom: 1px solid $border-color;\r\n}\r\n\r\n.blog-content {\r\n    display: flex;\r\n    flex-direction: column;\r\n    height: 100%;\r\n    flex-grow: 1;\r\n  a h3 {\r\n    color: var(--text-color, #2c2c2c);\r\n    font-size: 20px;\r\n    font-style: normal;\r\n    font-weight: 600;\r\n    line-height: normal;\r\n  }\r\n\r\n  p {\r\n    color: var(--text-color, #2C2C2C);\r\nfont-size: 14px;\r\nfont-style: normal;\r\nfont-weight: 400;\r\nline-height: normal;\r\n  }\r\n\r\n\r\n  .link {\r\n    font-weight: 500;\r\n    color: #30AB89\r\n  }\r\n}\r\n","/*------------------------------------\r\nSECTION TESTIMONIAL\r\n-------------------------------------*/\r\n#section-testimonial{\r\n    position: relative;\r\n    padding: 20px;\r\n    -webkit-background-size: cover;\r\n    background-size: cover;\r\n    background-color: #101010;}\r\n.mb25{\r\n    margin-bottom: 25px;\r\n}\r\n\r\n.testimonial-container {\r\n    margin: auto;\r\n    max-width: 1540px;\r\n    \r\n    margin: 80px auto;\r\n  \r\n    @media (max-width: 1154px) {\r\n      margin: 50px auto;\r\n    }\r\n  }\r\n  \r\n.test-inner{\r\n    display: flex;\r\n    padding: 24px;\r\n    flex-direction: column;\r\n    justify-content: center;\r\n    align-items: flex-start;\r\n    gap: 22px;\r\n    color: var(--white-color, #FAFAFA);\r\n    font-size: 14px;\r\n    font-style: normal;\r\n    font-weight: 400;\r\n    line-height: normal;\r\n    border-radius: 32px;\r\n    border: 2px solid var(--main-color-1, #30AB89);\r\n    min-height: 254px;\r\n\r\n    @media screen and (max-width: 768px) {\r\n        margin-bottom: 1rem;\r\n    }\r\n}\r\n\r\n\r\n.test-author-thumb{\r\n    align-items: center;\r\n    gap: 1rem;\r\n    // margin-bottom: 15px;\r\n    img{\r\n        width: 56px;\r\n        height: 56px;\r\n        border-radi