olute;\r\n  left: -55px;\r\n  width: 35px;\r\n  height: 35px;\r\n  top: 50%;\r\n  transform: translateY(-55%);\r\n  border: 1px solid #2C2C2C;\r\n  border-radius: 50%;\r\n  display: flex;\r\n  justify-content: center;\r\n  align-items: center;\r\n  font-size: 20px;\r\nfont-style: normal;\r\nfont-weight: 600;\r\nline-height: 35px; \r\ncolor: #2C2C2C;\r\n}\r\n\r\n.block-list__item:first-child {\r\n  margin-left: 0;\r\n}\r\n#third {\r\n  background: #f5f5f5;\r\n}\r\n.scrollend {\r\n  transform: translateX(-1500px);\r\n}\r\n.block-list {\r\n  counter-reset: element;   \r\n  list-style: none;\r\n}\r\n.scroll-content .mobile {\r\n  display: none;\r\n}\r\n\r\n@media(max-width: 767px) {\r\n  .section--vertical.desktop {\r\n    display: none;\r\n  }\r\n  .block-list__item-inner::before {\r\n    display: none;\r\n  }\r\n  .scroll-content .mobile {\r\n    display: block;\r\n  }\r\n}"]}